"use client";

import dynamic from "next/dynamic";
import { useState, useEffect, useRef } from "react";

const DeliveryMap = dynamic(() => import("./components/DeliveryMap"), {
  ssr: false,
  loading: () => (
    <div style={{
      height: 480, background: "#0a1628", borderRadius: 12,
      border: "1px solid #1e3a5a", display: "flex",
      alignItems: "center", justifyContent: "center",
      fontFamily: "monospace", color: "#1e3050", fontSize: 13
    }}>
      LOADING MAP...
    </div>
  ),
});

// ─── Types ────────────────────────────────────────────────────────────────────

interface AgentStatus {
  state: "idle" | "running" | "done" | "error";
  startedAt?: number;
  duration?: number;
}

interface Assignment {
  vehicle_id: string;
  driver: string;
  vehicle_type: string;
  assigned_order_ids: string[];
  area_types_covered: string[];
  total_weight_kg: number;
  capacity_kg: number;
  estimated_co2_kg: number;
  route_sequence: string[];
  high_priority_count: number;
  flagged_orders: { order_id: string; flag: string; recommendation: string }[];
  reasoning: string;
}

interface RouteSummary {
  total_orders: number;
  total_vehicles_used: number;
  urban_orders: number;
  rural_orders: number;
  semi_urban_orders: number;
  ev_orders: number;
  diesel_orders: number;
  estimated_total_co2_kg: number;
  diesel_baseline_co2_kg: number;
  co2_saved_kg: number;
}

interface AreaForecast {
  area: string;
  area_type: string;
  avg_daily_orders: number;
  trend: string;
  predicted_tomorrow: number;
  demand_surge: boolean;
  recommendation: string;
}

interface Alert {
  order_id: string;
  alert_type: string;
  severity: "high" | "medium" | "low";
  area: string;
  area_type: string;
  message: string;
  corrective_action: string;
}

interface Debate {
  order_id: string;
  area: string;
  current_vehicle: string;
  optimizer_argument: string;
  alert_argument: string;
  cost_analysis: {
    cost_of_proceeding_inr: number;
    cost_of_override_inr: number;
    expected_saving_inr: number;
  };
  ruling: "UPHOLD" | "OVERRIDE";
  ruling_action: string;
  ruling_reasoning: string;
}

interface Arbitration {
  conflicts_detected: number;
  debates: Debate[];
  final_overrides: {
    order_id: string;
    original_vehicle: string;
    override_action: string;
    estimated_saving_inr: number;
  }[];
  arbitrator_summary: string;
  consensus_reached: boolean;
}

interface OrchestrationResult {
  meta: { city: string; agents_run: string[]; debate_mode?: boolean };
  route_optimization: { assignments: Assignment[]; summary: RouteSummary };
  demand_forecast: {
    area_forecasts: AreaForecast[];
    pre_positioning: { vehicle_id: string; recommended_staging_area: string; reason: string }[];
    insight: string;
  };
  alerts: {
    alerts: Alert[];
    pattern_analysis: {
      most_problematic_area: string;
      most_common_failure_reason: string;
      rural_failure_rate_pct: number;
      insight: string;
    };
    rural_connectivity_recommendation: string;
    operational_risk_score: number;
    risk_justification: string;
  };
  arbitration?: Arbitration;
}

// ─── Constants ───────────────────────────────────────────────────────────────

const BACKEND = "http://localhost:5000";

const AGENT_META = {
  RouteOptimizer: {
    label: "Route Optimizer",
    icon: "⬡",
    desc: "Assigns orders to vehicles considering capacity, area type, traffic & CO₂",
    color: "#00e5ff",
  },
  DemandForecaster: {
    label: "Demand Forecaster",
    icon: "◈",
    desc: "Predicts tomorrow's demand from 7-day history & recommends pre-positioning",
    color: "#ff6b9d",
  },
  AlertAgent: {
    label: "Alert Agent",
    icon: "◉",
    desc: "Scans failed delivery patterns and flags at-risk orders",
    color: "#ffd166",
  },
  ArbitratorAgent: {
    label: "Arbitrator",
    icon: "⚖",
    desc: "Resolves conflicts between Route Optimizer & Alert Agent with cost reasoning",
    color: "#a78bfa",
  },
};

const SUGGESTED_COMMANDS = [
  "Prioritize all medicine orders",
  "Avoid Koramangala due to flooding",
  "Maximize EV usage, minimize diesel",
  "Flag all rural orders for SMS confirmation",
  "Emergency: reassign EV-01 orders to TRUCK-01",
];

const MAP_ORDERS = [
  { order_id: "ORD-101", location_name: "Indiranagar", lat: 12.9784, lng: 77.6408, area_type: "urban", priority: "high", weight_kg: 10, deadline_hours: 2, attempt_count: 0, item_category: "electronics" },
  { order_id: "ORD-102", location_name: "Whitefield", lat: 12.9698, lng: 77.7500, area_type: "urban", priority: "medium", weight_kg: 15, deadline_hours: 4, attempt_count: 0, item_category: "groceries" },
  { order_id: "ORD-103", location_name: "Devanahalli", lat: 13.2431, lng: 77.7160, area_type: "rural", priority: "low", weight_kg: 5, deadline_hours: 8, attempt_count: 1, item_category: "medicines" },
  { order_id: "ORD-104", location_name: "Koramangala", lat: 12.9352, lng: 77.6245, area_type: "urban", priority: "high", weight_kg: 20, deadline_hours: 1, attempt_count: 0, item_category: "perishables" },
  { order_id: "ORD-105", location_name: "Doddaballapura", lat: 13.2963, lng: 77.5373, area_type: "rural", priority: "medium", weight_kg: 8, deadline_hours: 6, attempt_count: 0, item_category: "clothing" },
  { order_id: "ORD-106", location_name: "HSR Layout", lat: 12.9116, lng: 77.6474, area_type: "urban", priority: "low", weight_kg: 12, deadline_hours: 5, attempt_count: 0, item_category: "furniture" },
  { order_id: "ORD-107", location_name: "Yelahanka", lat: 13.1005, lng: 77.5963, area_type: "semi-urban", priority: "high", weight_kg: 18, deadline_hours: 2, attempt_count: 0, item_category: "electronics" },
  { order_id: "ORD-108", location_name: "Nelamangala", lat: 13.0989, lng: 77.3938, area_type: "rural", priority: "medium", weight_kg: 10, deadline_hours: 7, attempt_count: 2, item_category: "medicines" },
  { order_id: "ORD-109", location_name: "Bannerghatta", lat: 12.8000, lng: 77.5757, area_type: "semi-urban", priority: "low", weight_kg: 7, deadline_hours: 6, attempt_count: 0, item_category: "groceries" },
  { order_id: "ORD-110", location_name: "Electronic City", lat: 12.8458, lng: 77.6603, area_type: "urban", priority: "high", weight_kg: 25, deadline_hours: 1, attempt_count: 0, item_category: "perishables" },
  { order_id: "ORD-111", location_name: "Hoskote", lat: 13.0709, lng: 77.7980, area_type: "rural", priority: "medium", weight_kg: 9, deadline_hours: 8, attempt_count: 1, item_category: "clothing" },
  { order_id: "ORD-112", location_name: "Malleshwaram", lat: 13.0035, lng: 77.5703, area_type: "urban", priority: "high", weight_kg: 3, deadline_hours: 2, attempt_count: 0, item_category: "medicines" },
  { order_id: "ORD-113", location_name: "Kanakapura", lat: 12.5462, lng: 77.4175, area_type: "rural", priority: "low", weight_kg: 14, deadline_hours: 10, attempt_count: 0, item_category: "groceries" },
  { order_id: "ORD-114", location_name: "Rajajinagar", lat: 12.9906, lng: 77.5530, area_type: "urban", priority: "medium", weight_kg: 11, deadline_hours: 3, attempt_count: 0, item_category: "electronics" },
  { order_id: "ORD-115", location_name: "Tumkur Road", lat: 13.0550, lng: 77.4700, area_type: "semi-urban", priority: "high", weight_kg: 22, deadline_hours: 3, attempt_count: 0, item_category: "perishables" },
];

// ─── Helpers ─────────────────────────────────────────────────────────────────

function severityColor(s: string) {
  if (s === "high") return "#ff4d6d";
  if (s === "medium") return "#ffd166";
  return "#06d6a0";
}

function areaColor(t: string) {
  if (t === "urban") return "#00e5ff";
  if (t === "rural") return "#ffd166";
  return "#ff6b9d";
}

function vehicleIcon(type: string) {
  if (type === "electric") return "⚡";
  if (type === "electric_bike") return "🛵";
  return "🚛";
}

function trendIcon(t: string) {
  if (t === "growing") return "↑";
  if (t === "declining") return "↓";
  return "→";
}

// ─── Sub-components ──────────────────────────────────────────────────────────

function AgentCard({ name, status, log }: { name: keyof typeof AGENT_META; status: AgentStatus; log: string[] }) {
  const meta = AGENT_META[name];
  const isRunning = status.state === "running";
  const isDone = status.state === "done";
  const isError = status.state === "error";

  return (
    <div style={{
      border: `1px solid ${isDone ? meta.color : isRunning ? meta.color : "#1e2a3a"}`,
      borderRadius: 12, padding: "14px 16px",
      background: isRunning ? `linear-gradient(135deg, #0a1628 0%, ${meta.color}11 100%)` : "#0a1628",
      transition: "all 0.4s ease", position: "relative", overflow: "hidden",
    }}>
      {isRunning && (
        <div style={{
          position: "absolute", top: 0, left: 0, height: 2, width: "100%",
          background: `linear-gradient(90deg, transparent, ${meta.color}, transparent)`,
          animation: "scanline 1.5s linear infinite",
        }} />
      )}
      <div style={{ display: "flex", alignItems: "flex-start", gap: 10, marginBottom: 6 }}>
        <span style={{
          fontSize: 20, color: meta.color, flexShrink: 0, marginTop: 1,
          filter: isRunning ? `drop-shadow(0 0 8px ${meta.color})` : "none",
          animation: isRunning ? "pulse 1s ease-in-out infinite" : "none",
        }}>{meta.icon}</span>
        <div style={{ flex: 1, minWidth: 0 }}>
          <div style={{ fontFamily: "'Space Mono', monospace", fontSize: 11, color: meta.color, fontWeight: 700 }}>
            {meta.label.toUpperCase()}
          </div>
          <div style={{ fontSize: 9, color: "#3a5070", marginTop: 2, lineHeight: 1.3 }}>{meta.desc}</div>
        </div>
        <div style={{ flexShrink: 0, textAlign: "right" }}>
          {status.state === "idle" && <span style={{ fontSize: 8, color: "#2a3a4a", fontFamily: "monospace", fontWeight: 600 }}>WAIT</span>}
          {isRunning && <span style={{ fontSize: 8, color: meta.color, fontFamily: "monospace", animation: "blink 1s step-end infinite", fontWeight: 600 }}>RUN</span>}
          {isDone && <span style={{ fontSize: 8, color: "#06d6a0", fontFamily: "monospace", fontWeight: 600 }}>✓ {status.duration?.toFixed(1)}s</span>}
          {isError && <span style={{ fontSize: 8, color: "#ff4d6d", fontFamily: "monospace", fontWeight: 600 }}>✗ ERR</span>}
        </div>
      </div>
      {log.length > 0 && (
        <div style={{
          marginTop: 8, padding: "6px 8px", background: "#050d1a", borderRadius: 4,
          fontSize: 8, fontFamily: "'Space Mono', monospace", color: "#4a6080",
          maxHeight: 48, overflowY: "auto", lineHeight: 1.4,
        }}>
          {log.slice(-3).map((l, i) => (
            <div key={i} style={{ color: i === log.length - 1 ? "#7a9abf" : "#3a5070" }}>{l}</div>
          ))}
        </div>
      )}
    </div>
  );
}

function KpiCard({ label, value, sub, color }: { label: string; value: string | number; sub?: string; color: string }) {
  return (
    <div style={{
      background: "#0a1628", border: `1px solid ${color}33`,
      borderRadius: 10, padding: "14px 16px", position: "relative", overflow: "hidden",
    }}>
      <div style={{
        position: "absolute", top: 0, left: 0, width: 2.5, height: "100%",
        background: color, borderRadius: "10px 0 0 10px", opacity: 0.8,
      }} />
      <div style={{ fontSize: 9, color: color, fontFamily: "monospace", letterSpacing: 1, marginBottom: 5, fontWeight: 600 }}>
        {label.toUpperCase()}
      </div>
      <div style={{ fontSize: 24, fontFamily: "'Space Mono', monospace", color, fontWeight: 700, lineHeight: 1, marginBottom: 4 }}>
        {value}
      </div>
      {sub && <div style={{ fontSize: 9, color: "#3a5070", fontFamily: "monospace" }}>↳ {sub}</div>}
    </div>
  );
}

// ─── Debate Card ─────────────────────────────────────────────────────────────

function DebateCard({ debate, index }: { debate: Debate; index: number }) {
  const [visible, setVisible] = useState(false);
  const [phase, setPhase] = useState<"optimizer" | "alert" | "ruling">("optimizer");

  useEffect(() => {
    // Staggered reveal — each card appears after the previous
    const t1 = setTimeout(() => setVisible(true), index * 800);
    const t2 = setTimeout(() => setPhase("alert"), index * 800 + 1200);
    const t3 = setTimeout(() => setPhase("ruling"), index * 800 + 2400);
    return () => { clearTimeout(t1); clearTimeout(t2); clearTimeout(t3); };
  }, [index]);

  if (!visible) return (
    <div style={{
      background: "#0a1628", border: "1px solid #1e2a3a",
      borderRadius: 12, padding: "20px 24px", opacity: 0.3,
      fontFamily: "monospace", fontSize: 11, color: "#2a4060",
    }}>
      ⚖ Preparing case for {debate.order_id}...
    </div>
  );

  const isOverride = debate.ruling === "OVERRIDE";

  return (
    <div style={{
      background: "#0a1628",
      border: `1px solid ${isOverride ? "#a78bfa44" : "#06d6a044"}`,
      borderRadius: 12, padding: "20px 24px",
      animation: "fadeIn 0.5s ease forwards",
    }}>
      {/* Header */}
      <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 16 }}>
        <div style={{
          width: 32, height: 32, borderRadius: 8,
          background: isOverride ? "#a78bfa22" : "#06d6a022",
          border: `1px solid ${isOverride ? "#a78bfa" : "#06d6a0"}`,
          display: "flex", alignItems: "center", justifyContent: "center", fontSize: 16,
        }}>⚖</div>
        <div>
          <div style={{ fontSize: 13, fontFamily: "monospace", color: "#e8f4ff", fontWeight: 700 }}>
            {debate.order_id} — {debate.area}
          </div>
          <div style={{ fontSize: 11, color: "#4a6080" }}>Currently assigned: {debate.current_vehicle}</div>
        </div>
        <div style={{ marginLeft: "auto" }}>
          <span style={{
            fontSize: 11, fontFamily: "monospace", fontWeight: 700,
            padding: "4px 12px", borderRadius: 20,
            background: isOverride ? "#a78bfa22" : "#06d6a022",
            border: `1px solid ${isOverride ? "#a78bfa" : "#06d6a0"}`,
            color: isOverride ? "#a78bfa" : "#06d6a0",
          }}>
            {isOverride ? "⚠ OVERRIDE" : "✓ UPHOLD"}
          </span>
        </div>
      </div>

      {/* Arguments */}
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12, marginBottom: 16 }}>
        {/* Optimizer argument */}
        <div style={{
          background: "#050d1a", border: "1px solid #00e5ff22",
          borderRadius: 8, padding: "12px 14px",
          opacity: phase === "optimizer" || phase === "alert" || phase === "ruling" ? 1 : 0,
          transition: "opacity 0.5s",
        }}>
          <div style={{ fontSize: 9, fontFamily: "monospace", color: "#00e5ff", letterSpacing: 1, marginBottom: 8 }}>
            ⬡ ROUTE OPTIMIZER ARGUES
          </div>
          <p style={{ fontSize: 11, color: "#6a9abf", lineHeight: 1.7 }}>{debate.optimizer_argument}</p>
        </div>

        {/* Alert argument */}
        <div style={{
          background: "#050d1a", border: "1px solid #ff4d6d22",
          borderRadius: 8, padding: "12px 14px",
          opacity: phase === "alert" || phase === "ruling" ? 1 : 0.2,
          transition: "opacity 0.6s ease",
        }}>
          <div style={{ fontSize: 9, fontFamily: "monospace", color: "#ff4d6d", letterSpacing: 1, marginBottom: 8 }}>
            ◉ ALERT AGENT CHALLENGES
          </div>
          <p style={{ fontSize: 11, color: "#6a9abf", lineHeight: 1.7 }}>{debate.alert_argument}</p>
        </div>
      </div>

      {/* Cost analysis */}
      {debate.cost_analysis && (
        <div style={{
          display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 8, marginBottom: 14,
          opacity: phase === "ruling" ? 1 : 0.2, transition: "opacity 0.6s ease",
        }}>
          {[
            { label: "Cost if proceed", value: `₹${debate.cost_analysis.cost_of_proceeding_inr?.toLocaleString("en-IN") || 0}`, color: "#ff4d6d" },
            { label: "Cost if override", value: `₹${debate.cost_analysis.cost_of_override_inr?.toLocaleString("en-IN") || 0}`, color: "#ffd166" },
            { label: "Expected saving", value: `₹${debate.cost_analysis.expected_saving_inr?.toLocaleString("en-IN") || 0}`, color: "#06d6a0" },
          ].map((item) => (
            <div key={item.label} style={{
              background: "#050d1a", borderRadius: 8, padding: "10px 12px",
              border: `1px solid ${item.color}22`, textAlign: "center",
            }}>
              <div style={{ fontSize: 9, fontFamily: "monospace", color: "#3a5070", marginBottom: 4 }}>{item.label.toUpperCase()}</div>
              <div style={{ fontSize: 16, fontFamily: "'Space Mono', monospace", color: item.color, fontWeight: 700 }}>{item.value}</div>
            </div>
          ))}
        </div>
      )}

      {/* Ruling */}
      <div style={{
        background: isOverride ? "#a78bfa11" : "#06d6a011",
        border: `1px solid ${isOverride ? "#a78bfa33" : "#06d6a033"}`,
        borderRadius: 8, padding: "12px 14px",
        opacity: phase === "ruling" ? 1 : 0,
        transition: "opacity 0.6s ease",
        borderLeft: `4px solid ${isOverride ? "#a78bfa" : "#06d6a0"}`,
      }}>
        <div style={{ fontSize: 9, fontFamily: "monospace", color: isOverride ? "#a78bfa" : "#06d6a0", letterSpacing: 1, marginBottom: 6 }}>
          ⚖ ARBITRATOR RULING · {debate.ruling}
        </div>
        {isOverride && (
          <div style={{ fontSize: 11, color: "#a78bfa", fontFamily: "monospace", marginBottom: 6 }}>
            ACTION: {debate.ruling_action}
          </div>
        )}
        <p style={{ fontSize: 11, color: "#8ab0d0", lineHeight: 1.7 }}>{debate.ruling_reasoning}</p>
      </div>
    </div>
  );
}

// ─── Main Page ────────────────────────────────────────────────────────────────

export default function Dashboard() {
  const [agentStatus, setAgentStatus] = useState<Record<string, AgentStatus>>({
    RouteOptimizer: { state: "idle" },
    DemandForecaster: { state: "idle" },
    AlertAgent: { state: "idle" },
    ArbitratorAgent: { state: "idle" },
  });
  const [agentLogs, setAgentLogs] = useState<Record<string, string[]>>({
    RouteOptimizer: [], DemandForecaster: [], AlertAgent: [], ArbitratorAgent: [],
  });
  const [result, setResult] = useState<OrchestrationResult | null>(null);
  const [isRunning, setIsRunning] = useState(false);
  const [debateMode, setDebateMode] = useState(false);
  const [activeTab, setActiveTab] = useState<"routes" | "forecast" | "alerts" | "analytics" | "debate">("routes");
  const [orchestratorLog, setOrchestratorLog] = useState<string[]>([]);
  const [injecting, setInjecting] = useState(false);
  const [injectedOrderId, setInjectedOrderId] = useState<string | null>(null);
  const [liveDebates, setLiveDebates] = useState<Debate[]>([]);
  const [conflictAlert, setConflictAlert] = useState<string | null>(null);
  const [analytics, setAnalytics] = useState<any>(null);
  const [eoqData, setEoqData] = useState<any>(null);

  // Command bar state
  const [command, setCommand] = useState("");
  const [commandHistory, setCommandHistory] = useState<string[]>([]);

  const logRef = useRef<HTMLDivElement>(null);
  const startTimes = useRef<Record<string, number>>({});

  useEffect(() => {
    if (logRef.current) logRef.current.scrollTop = logRef.current.scrollHeight;
  }, [orchestratorLog]);

  const addLog = (msg: string) => {
    setOrchestratorLog(prev => [...prev, `[${new Date().toLocaleTimeString()}] ${msg}`]);
  };

  const addAgentLog = (agent: string, msg: string) => {
    setAgentLogs(prev => ({ ...prev, [agent]: [...(prev[agent] || []), msg] }));
  };

  const resetState = (includeDebate = false) => {
    setResult(null);
    setLiveDebates([]);
    setConflictAlert(null);
    setOrchestratorLog([]);
    setAgentLogs({ RouteOptimizer: [], DemandForecaster: [], AlertAgent: [], ArbitratorAgent: [] });
    const base: Record<string, AgentStatus> = {
      RouteOptimizer: { state: "idle" },
      DemandForecaster: { state: "idle" },
      AlertAgent: { state: "idle" },
      ArbitratorAgent: { state: "idle" },
    };
    setAgentStatus(base);
  };

  const handleStream = (es: EventSource) => {
    es.onmessage = (e) => {
      const { event, payload } = JSON.parse(e.data);

      if (event === "orchestrator_start") {
        addLog(`Orchestrator initialized — ${payload.total_orders} orders, ${payload.total_vehicles} vehicles, ${payload.city}${payload.debate_mode ? " · DEBATE MODE ON" : ""}`);
      }
      if (event === "agent_start") {
        startTimes.current[payload.agent] = Date.now();
        setAgentStatus(prev => ({ ...prev, [payload.agent]: { state: "running", startedAt: Date.now() } }));
        addLog(`▶ ${payload.agent}: ${payload.message}`);
        addAgentLog(payload.agent, payload.message);
      }
      if (event === "agent_complete") {
        const duration = payload.duration || ((Date.now() - (startTimes.current[payload.agent] || Date.now())) / 1000);
        setAgentStatus(prev => ({ ...prev, [payload.agent]: { state: "done", duration } }));
        const toolInfo = payload.tool_calls_made ? ` — ${payload.tool_calls_made} tool calls` : "";
        addLog(`✓ ${payload.agent} completed in ${typeof duration === "number" ? duration.toFixed(1) : duration}s${toolInfo}`);
        addAgentLog(payload.agent, `Completed in ${typeof duration === "number" ? duration.toFixed(1) : duration}s`);
      }
      if (event === "agent_error") {
        setAgentStatus(prev => ({ ...prev, [payload.agent]: { state: "error" } }));
        addLog(`✗ ${payload.agent} error: ${payload.error}`);
      }
      // Debate-specific events
      if (event === "debate_start") {
        setConflictAlert(payload.message);
        addLog(`⚖ ${payload.message}`);
        // Switch to debate tab automatically
        setActiveTab("debate");
      }
      if (event === "debate_ruling") {
        setLiveDebates(prev => [...prev, payload.debate]);
        const d = payload.debate;
        addLog(`⚖ ${d.order_id}: Arbitrator ruled ${d.ruling} — ${d.ruling_action || "assignment upheld"}`);
      }
      if (event === "orchestration_complete") {
        addLog("All agents complete. Rendering results...");
        setResult(payload as OrchestrationResult);
        // If debate results came in payload, set them
        if (payload.arbitration?.debates?.length > 0) {
          setLiveDebates(payload.arbitration.debates);
        }
        setIsRunning(false);
        es.close();

        // Fetch analytics (ARIMA + Hurst)
        fetch(`${BACKEND}/api/analytics`)
          .then(res => res.json())
          .then(data => setAnalytics(data))
          .catch(err => console.error("Analytics fetch error:", err));

        // Fetch EOQ
        fetch(`${BACKEND}/api/eoq`)
          .then(res => res.json())
          .then(data => setEoqData(data))
          .catch(err => console.error("EOQ fetch error:", err));
      }
    };
    es.onerror = () => {
