  // ── Run with natural language command ──
  const runCommand = async () => {
    const cmd = command.trim();
    if (!cmd || isRunning) return;

    setIsRunning(true);
    resetState();
    setCommandHistory(prev => [cmd, ...prev.slice(0, 4)]);
    setCommand("");

    addLog(`⌘ Command: "${cmd}"`);
    addLog("Injecting instruction into agents...");

    try {
      await fetch(`${BACKEND}/api/command`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ command: cmd }),
