      customer_name: "Urgent Customer",
      location_name: "MG Road",
      area_type: "urban",
      lat: 12.9756,
      lng: 77.6099,
      priority: "high",
      weight_kg: 8,
      deadline_hours: 1,
      item_category: "medicines",
      status: "pending",
      attempt_count: 0,
      delivery_window: "ASAP",
