    try {
      addLog(`⚡ LIVE ORDER INJECTED: ${urgentOrder.order_id} — MG Road — medicines — 1hr deadline`);
      const res = await fetch(`${BACKEND}/api/inject-order`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(urgentOrder),
