        body { background: #030b18; color: #c8d8e8; font-family: 'Syne', sans-serif; }
        ::-webkit-scrollbar { width: 4px; }
        ::-webkit-scrollbar-track { background: #050d1a; }
        ::-webkit-scrollbar-thumb { background: #1e3a5a; border-radius: 2px; }
