        .run-btn:hover:not(:disabled) { transform: translateY(-2px); box-shadow: 0 8px 30px rgba(0,229,255,0.3); }
        .debate-btn:hover:not(:disabled) { transform: translateY(-2px); box-shadow: 0 8px 30px rgba(167,139,250,0.3) !important; }
        .run-btn:disabled { opacity: 0.5; cursor: not-allowed; }
        .card-hover { transition: border-color 0.2s, transform 0.2s; }
        .card-hover:hover { transform: translateY(-2px); border-color: #1e3a5a !important; }
        .cmd-chip:hover { color: #00e5ff !important; border-color: #00e5ff33 !important; }
