              const totalSavings = (arbitration?.final_overrides || []).reduce((s: number, o: any) => s + (o.estimated_saving_inr || 0), 0);
              const kpiList = [
                { label: "Total Orders", value: summary.total_orders, sub: "dispatched", color: "#00e5ff" },
