                { label: "Rural Covered", value: summary.rural_orders, sub: "zones", color: "#ffd166" },
                { label: "CO₂ Saved", value: `${summary.co2_saved_kg?.toFixed(1)}kg`, sub: "trees", color: "#06d6a0" },
                { label: "Cost Saved", value: `₹${evCostSaved.toLocaleString("en-IN", { notation: "compact" })}`, sub: "EV opt", color: "#06d6a0" },
                { label: "EV Orders", value: summary.ev_orders, sub: "zero-emit", color: "#00e5ff" },
