                      background: activeTab === tab ? (tab === "debate" ? "#a78bfa15" : tab === "analytics" ? "#ff6b9d15" : "#00e5ff15") : "transparent",
                      border: activeTab === tab ? `1.5px solid ${tab === "debate" ? "#a78bfa" : tab === "analytics" ? "#ff6b9d" : "#00e5ff"}` : "1px solid #1e3a5a",
