                      </div>
                      <div style={{ fontSize: 11, color: "#3a5070", lineHeight: 1.6, borderTop: "1px solid #0e2040", paddingTop: 10 }}>{a.reasoning}</div>
                      {a.flagged_orders?.length > 0 && (
                        <div style={{ marginTop: 10 }}>
                          {a.flagged_orders.map((f, i) => (
                            <div key={i} style={{ fontSize: 10, color: "#ffd166", background: "#ffd16611", border: "1px solid #ffd16633", borderRadius: 6, padding: "6px 8px", marginTop: 4 }}>
                              ⚠ {f.order_id}: {f.recommendation}
                            </div>
                          ))}
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              )}

              {/* Forecast Tab */}
              {activeTab === "forecast" && (
                <div>
                  {result.demand_forecast?.insight && (
                    <div style={{ background: "#0a1628", border: "1px solid #ff6b9d33", borderRadius: 10, padding: "14px 18px", marginBottom: 20 }}>
                      <div style={{ fontSize: 10, fontFamily: "monospace", color: "#ff6b9d", letterSpacing: 1, marginBottom: 6 }}>◈ FORECAST INSIGHT</div>
                      <p style={{ fontSize: 13, color: "#8ab0d0", lineHeight: 1.7 }}>{result.demand_forecast.insight}</p>
                    </div>
                  )}
                  <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))", gap: 10, marginBottom: 20 }}>
                    {result.demand_forecast?.area_forecasts?.map((f) => (
                      <div key={f.area} className="card-hover" style={{
                        background: "#0a1628", border: `1px solid ${f.demand_surge ? "#ff4d6d44" : "#0e2040"}`,
                        borderRadius: 10, padding: "14px 16px",
                      }}>
                        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 8 }}>
                          <div>
                            <div style={{ fontSize: 12, color: "#e8f4ff", fontWeight: 600, marginBottom: 3 }}>{f.area}</div>
                            <span style={{ fontSize: 9, fontFamily: "monospace", padding: "2px 6px", borderRadius: 20, border: `1px solid ${areaColor(f.area_type)}44`, color: areaColor(f.area_type) }}>
                              {f.area_type?.toUpperCase()}
                            </span>
                          </div>
                          <div style={{ textAlign: "right" }}>
                            <div style={{ fontSize: 22, fontFamily: "'Space Mono', monospace", color: f.demand_surge ? "#ff4d6d" : "#ff6b9d", fontWeight: 700 }}>{f.predicted_tomorrow}</div>
                            <div style={{ fontSize: 9, color: "#2a4060" }}>tomorrow</div>
                          </div>
                        </div>
                        <div style={{ display: "flex", justifyContent: "space-between", fontSize: 11, color: "#3a5070", marginBottom: 8 }}>
                          <span>avg {f.avg_daily_orders}/day</span>
                          <span style={{ color: f.trend === "growing" ? "#06d6a0" : f.trend === "declining" ? "#ff4d6d" : "#ffd166" }}>
                            {trendIcon(f.trend)} {f.trend}
                          </span>
                        </div>
                        {f.demand_surge && (
                          <div style={{ fontSize: 10, color: "#ff4d6d", background: "#ff4d6d11", borderRadius: 5, padding: "4px 8px", marginBottom: 6 }}>⚡ DEMAND SURGE DETECTED</div>
                        )}
                        <div style={{ fontSize: 10, color: "#3a5070", lineHeight: 1.5 }}>{f.recommendation}</div>
                      </div>
                    ))}
                  </div>
                  {result.demand_forecast?.pre_positioning?.length > 0 && (
                    <div style={{ background: "#0a1628", border: "1px solid #0e2040", borderRadius: 10, padding: "14px 18px" }}>
                      <div style={{ fontSize: 10, fontFamily: "monospace", color: "#00e5ff", letterSpacing: 1, marginBottom: 12 }}>PRE-POSITIONING RECOMMENDATIONS</div>
                      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(280px, 1fr))", gap: 10 }}>
                        {result.demand_forecast.pre_positioning.map((p, i) => (
                          <div key={i} style={{ display: "flex", gap: 10, padding: "10px 12px", background: "#050d1a", borderRadius: 8 }}>
                            <span style={{ fontSize: 16 }}>📍</span>
                            <div>
                              <div style={{ fontSize: 12, color: "#00e5ff", fontFamily: "monospace", marginBottom: 3 }}>{p.vehicle_id} → {p.recommended_staging_area}</div>
                              <div style={{ fontSize: 11, color: "#3a5070" }}>{p.reason}</div>
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              )}

              {/* Alerts Tab */}
              {activeTab === "alerts" && (
                <div>
                  {result.alerts?.pattern_analysis && (
                    <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(280px, 1fr))", gap: 12, marginBottom: 20 }}>
                      <div style={{ background: "#0a1628", border: "1px solid #ffd16633", borderRadius: 10, padding: "14px 18px" }}>
                        <div style={{ fontSize: 10, fontFamily: "monospace", color: "#ffd166", letterSpacing: 1, marginBottom: 8 }}>PATTERN ANALYSIS</div>
                        <div style={{ fontSize: 12, color: "#8ab0d0", lineHeight: 1.7 }}>
                          <div>Most problematic: <span style={{ color: "#ffd166" }}>{result.alerts.pattern_analysis.most_problematic_area}</span></div>
                          <div>Common failure: <span style={{ color: "#ffd166" }}>{result.alerts.pattern_analysis.most_common_failure_reason}</span></div>
                          <div>Rural failure rate: <span style={{ color: "#ff4d6d" }}>{result.alerts.pattern_analysis.rural_failure_rate_pct}%</span></div>
                        </div>
                        <div style={{ fontSize: 11, color: "#3a5070", marginTop: 10, lineHeight: 1.6 }}>{result.alerts.pattern_analysis.insight}</div>
                      </div>
                      <div style={{ background: "#0a1628", border: "1px solid #06d6a033", borderRadius: 10, padding: "14px 18px" }}>
                        <div style={{ fontSize: 10, fontFamily: "monospace", color: "#06d6a0", letterSpacing: 1, marginBottom: 8 }}>RURAL CONNECTIVITY FIX</div>
                        <p style={{ fontSize: 12, color: "#8ab0d0", lineHeight: 1.7 }}>{result.alerts.rural_connectivity_recommendation}</p>
                      </div>
                    </div>
                  )}
                  <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(320px, 1fr))", gap: 10 }}>
                    {result.alerts?.alerts?.map((a, i) => (
                      <div key={i} className="card-hover" style={{
                        background: "#0a1628", border: `1px solid ${severityColor(a.severity)}44`,
                        borderRadius: 10, padding: "14px 18px",
                      }}>
                        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 8 }}>
                          <div>
                            <span style={{ fontSize: 9, fontFamily: "monospace", padding: "2px 8px", borderRadius: 20, border: `1px solid ${severityColor(a.severity)}66`, color: severityColor(a.severity), background: `${severityColor(a.severity)}11` }}>
                              {a.severity.toUpperCase()}
                            </span>
                            <span style={{ fontSize: 9, fontFamily: "monospace", color: "#2a4060", marginLeft: 6 }}>{a.alert_type}</span>
                          </div>
                          <span style={{ fontSize: 11, fontFamily: "monospace", color: "#4a6080" }}>{a.order_id}</span>
                        </div>
                        <div style={{ fontSize: 12, color: "#8ab0d0", marginBottom: 6 }}>{a.area} <span style={{ color: areaColor(a.area_type), fontSize: 10 }}>({a.area_type})</span></div>
                        <div style={{ fontSize: 12, color: "#c8d8e8", marginBottom: 8, lineHeight: 1.6 }}>{a.message}</div>
                        <div style={{ fontSize: 11, color: "#06d6a0", background: "#06d6a011", border: "1px solid #06d6a033", borderRadius: 6, padding: "6px 10px" }}>
                          ✓ {a.corrective_action}
                        </div>
                      </div>
                    ))}
                  </div>
                  {/* Rural Fallback Protocol */}
                  <div style={{ marginTop: 20, background: "#0a1628", border: "1px solid #ffd16644", borderRadius: 12, padding: "20px 24px" }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 16 }}>
                      <span style={{ fontSize: 20 }}>📡</span>
                      <div>
                        <div style={{ fontSize: 10, fontFamily: "monospace", color: "#ffd166", letterSpacing: 2 }}>RURAL FALLBACK PROTOCOL — ACTIVE</div>
                        <div style={{ fontSize: 12, color: "#4a6080", marginTop: 2 }}>Low-connectivity zones: Nelamangala · Kanakapura · Devanahalli · Hoskote</div>
                      </div>
                      <div style={{ marginLeft: "auto", fontSize: 10, fontFamily: "monospace", color: "#06d6a0", background: "#06d6a011", border: "1px solid #06d6a033", borderRadius: 20, padding: "4px 12px" }}>● PROTOCOL ARMED</div>
                    </div>
                    <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))", gap: 12 }}>
                      {[
                        { step: "01", icon: "💬", title: "SMS Pre-Confirmation", desc: "Automated SMS sent 2hrs before dispatch. Customer confirms availability. Reduces failed attempts by ~60%.", color: "#00e5ff" },
                        { step: "02", icon: "🤝", title: "Local Partner Network", desc: "Rural orders reassigned to verified local delivery partners with ground knowledge of area roads.", color: "#ff6b9d" },
                        { step: "03", icon: "📦", title: "Community Locker Drop-off", desc: "If customer unreachable, package deposited at nearest community locker or kirana store partner.", color: "#ffd166" },
                        { step: "04", icon: "🗺️", title: "Offline-First Driver App", desc: "Driver app caches route data locally. Works without internet in low-connectivity rural zones.", color: "#06d6a0" },
                      ].map((item) => (
                        <div key={item.step} style={{ background: "#050d1a", border: `1px solid ${item.color}22`, borderRadius: 10, padding: "14px 16px" }}>
                          <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 8 }}>
                            <span style={{ fontSize: 18 }}>{item.icon}</span>
                            <div>
                              <div style={{ fontSize: 9, fontFamily: "monospace", color: item.color, letterSpacing: 1 }}>STEP {item.step}</div>
                              <div style={{ fontSize: 12, color: "#e8f4ff", fontWeight: 600 }}>{item.title}</div>
                            </div>
                          </div>
                          <div style={{ fontSize: 11, color: "#3a5070", lineHeight: 1.6 }}>{item.desc}</div>
                        </div>
                      ))}
                    </div>
                    <div style={{ marginTop: 14, padding: "10px 14px", background: "#050d1a", borderRadius: 8, fontSize: 11, color: "#3a5070", lineHeight: 1.7, borderLeft: "3px solid #ffd166" }}>
                      <span style={{ color: "#ffd166", fontFamily: "monospace", fontSize: 10 }}>AGENT RECOMMENDATION · </span>
                      {result?.alerts?.rural_connectivity_recommendation || "Use offline-enabled mobile apps and community-based delivery models for rural last-mile coverage."}
                    </div>
                  </div>
                </div>
              )}

              {/* ── Analytics Tab ── */}
              {activeTab === "analytics" && analytics && (
                <div>
                  {/* ARIMA + Hurst Table with Header */}
                  <div style={{ marginBottom: 24 }}>
                    <div style={{ fontSize: 10, fontFamily: "monospace", color: "#00e5ff", letterSpacing: 2, marginBottom: 12 }}>
                      ⬡ DEMAND FORECAST (ARIMA) + ZONE STABILITY (HURST)
                    </div>
                    {/* Table Header */}
                    <div style={{
                      display: "grid", gridTemplateColumns: "1.2fr 1fr 1fr 1.5fr", gap: 14,
                      padding: "10px 16px", background: "#050d1a", borderRadius: 8, marginBottom: 8,
                      borderBottom: "1px solid #1e3a5a"
                    }}>
                      <div style={{ fontSize: 10, color: "#4a6080", fontWeight: 600 }}>ZONE</div>
                      <div style={{ fontSize: 10, color: "#4a6080", fontWeight: 600 }}>FORECAST</div>
                      <div style={{ fontSize: 10, color: "#4a6080", fontWeight: 600 }}>HURST</div>
                      <div style={{ fontSize: 10, color: "#4a6080", fontWeight: 600 }}>INTERPRETATION</div>
                    </div>
                    {/* Data Rows */}
                    <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
                      {analytics.analytics?.map((z: any) => (
                        <div key={z.order_id} style={{
                          background: "#0a1628", border: "1px solid #1e3a5a",
                          borderRadius: 8, padding: "12px 16px",
                          display: "grid", gridTemplateColumns: "1.2fr 1fr 1fr 1.5fr", gap: 14,
                          alignItems: "center"
                        }}>
                          <div>
                            <div style={{ fontSize: 12, color: "#e8f4ff", fontWeight: 600 }}>{z.zone}</div>
                            <div style={{ fontSize: 9, color: "#4a6080" }}>{z.area_type}</div>
                          </div>
                          <div>
                            <div style={{ fontSize: 13, color: "#00e5ff", fontFamily: "monospace", fontWeight: 700 }}>
                              {z.arima_forecast.predicted}
                            </div>
                            <div style={{ fontSize: 8, color: z.arima_forecast.trend === "up" ? "#06d6a0" : "#ff6b9d" }}>
                              {z.arima_forecast.trend === "up" ? "▲ Growing" : "▼ Declining"}
                            </div>
                          </div>
                          <div>
                            <div style={{ fontSize: 12, color: "#ffd166", fontFamily: "monospace", fontWeight: 700 }}>
                              {z.hurst.hurst}
                            </div>
                            <div style={{ fontSize: 8, color: z.hurst.risk_level === "high" ? "#ff4d6d" : z.hurst.risk_level === "medium" ? "#ffd166" : "#06d6a0", fontWeight: 600 }}>
                              {z.hurst.risk_level.toUpperCase()}
                            </div>
                          </div>
                          <div style={{ fontSize: 10, color: "#7a9abf", lineHeight: 1.4 }}>
                            {z.hurst.interpretation}
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>

                  {/* EOQ Table with Header */}
                  {eoqData && (
                    <div>
                      <div style={{ fontSize: 10, fontFamily: "monospace", color: "#ff6b9d", letterSpacing: 2, marginBottom: 12 }}>
                        ⬡ OPTIMAL ORDER QUANTITIES (BAYESIAN EOQ)
                      </div>
                      {/* Table Header */}
                      <div style={{
                        display: "grid", gridTemplateColumns: "1.2fr 1.2fr 1.2fr 1fr", gap: 14,
                        padding: "10px 16px", background: "#050d1a", borderRadius: 8, marginBottom: 8,
                        borderBottom: "1px solid #1e3a5a"
                      }}>
                        <div style={{ fontSize: 10, color: "#4a6080", fontWeight: 600 }}>ZONE</div>
                        <div style={{ fontSize: 10, color: "#4a6080", fontWeight: 600 }}>AVG DEMAND</div>
                        <div style={{ fontSize: 10, color: "#4a6080", fontWeight: 600 }}>REORDER QTY</div>
                        <div style={{ fontSize: 10, color: "#4a6080", fontWeight: 600 }}>REORDER PT</div>
                      </div>
                      {/* Data Rows */}
                      <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
                        {eoqData.eoq_recommendations?.slice(0, 8).map((z: any) => (
                          <div key={z.zone} style={{
                            background: "#0a1628", border: "1px solid #1e3a5a",
                            borderRadius: 8, padding: "12px 16px",
                            display: "grid", gridTemplateColumns: "1.2fr 1.2fr 1.2fr 1fr", gap: 14,
                            alignItems: "center"
                          }}>
                            <div>
                              <div style={{ fontSize: 12, color: "#e8f4ff", fontWeight: 600 }}>{z.zone}</div>
                              <div style={{ fontSize: 9, color: "#4a6080" }}>{z.area_type}</div>
                            </div>
                            <div>
                              <div style={{ fontSize: 13, color: "#00e5ff", fontFamily: "monospace", fontWeight: 700 }}>
                                {z.avg_daily_demand}
                              </div>
                              <div style={{ fontSize: 8, color: "#4a6080" }}>units/day</div>
                            </div>
                            <div>
                              <div style={{ fontSize: 13, color: "#06d6a0", fontFamily: "monospace", fontWeight: 700 }}>
                                {z.optimal_reorder_qty}
                              </div>
                              <div style={{ fontSize: 8, color: "#3a5070" }}>
                                [{z.credible_interval_95[0]}–{z.credible_interval_95[1]}]
                              </div>
                            </div>
                            <div>
                              <div style={{ fontSize: 12, color: "#ffd166", fontFamily: "monospace", fontWeight: 700 }}>
                                {z.reorder_point}
                              </div>
                              <div style={{ fontSize: 8, color: "#4a6080" }}>units</div>
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              )}

              {/* ── Debate / Arbitration Tab ── */}
              {activeTab === "debate" && (
                <div>
                  {/* Arbitrator summary banner */}
                  {arbitration?.arbitrator_summary && (
                    <div style={{
                      background: "#1a0a2e", border: "1px solid #a78bfa44",
                      borderRadius: 10, padding: "14px 18px", marginBottom: 24,
                    }}>
                      <div style={{ fontSize: 10, fontFamily: "monospace", color: "#a78bfa", letterSpacing: 1, marginBottom: 6 }}>⚖ ARBITRATOR SUMMARY</div>
                      <p style={{ fontSize: 13, color: "#8ab0d0", lineHeight: 1.7 }}>{arbitration.arbitrator_summary}</p>
                      <div style={{ display: "flex", gap: 16, marginTop: 12 }}>
                        <div style={{ fontSize: 12, color: "#4a6080" }}>
                          Conflicts: <span style={{ color: "#a78bfa", fontFamily: "monospace" }}>{arbitration.conflicts_detected}</span>
                        </div>
                        <div style={{ fontSize: 12, color: "#4a6080" }}>
                          Overrides: <span style={{ color: "#ff4d6d", fontFamily: "monospace" }}>{arbitration.final_overrides?.length || 0}</span>
                        </div>
                        <div style={{ fontSize: 12, color: "#4a6080" }}>
                          Upheld: <span style={{ color: "#06d6a0", fontFamily: "monospace" }}>{arbitration.conflicts_detected - (arbitration.final_overrides?.length || 0)}</span>
                        </div>
                      </div>
                    </div>
                  )}

                  {/* No conflicts case */}
                  {liveDebates.length === 0 && !isRunning && (
                    <div style={{
                      textAlign: "center", padding: "40px 0", color: "#2a4060",
                      fontFamily: "monospace", fontSize: 12,
                    }}>
                      {debateMode
                        ? "⚖ No conflicts detected. All Route Optimizer assignments approved."
                        : "Run ⚖ DEBATE MODE to see the Arbitrator Agent resolve conflicts between Route Optimizer and Alert Agent."}
                    </div>
                  )}

                  {/* Live debate cards — staggered reveal */}
                  <div style={{ display: "flex", flexDirection: "column", gap: 20 }}>
                    {liveDebates.map((debate, i) => (
                      <DebateCard key={debate.order_id} debate={debate} index={i} />
                    ))}
                  </div>

                  {/* Final overrides summary */}
                  {arbitration?.final_overrides && arbitration.final_overrides.length > 0 && (
                    <div style={{
                      marginTop: 24, background: "#0a1628",
                      border: "1px solid #a78bfa33", borderRadius: 12, padding: "18px 22px",
                    }}>
                      <div style={{ fontSize: 10, fontFamily: "monospace", color: "#a78bfa", letterSpacing: 2, marginBottom: 14 }}>
                        ⚖ FINAL OVERRIDE SUMMARY
                      </div>
                      <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
                        {arbitration.final_overrides.map((o: any, i: number) => (
                          <div key={i} style={{
                            display: "flex", alignItems: "center", gap: 14,
                            padding: "10px 14px", background: "#050d1a", borderRadius: 8,
                            border: "1px solid #a78bfa22",
                          }}>
                            <span style={{ fontSize: 16 }}>⚖</span>
                            <div style={{ flex: 1 }}>
                              <div style={{ fontSize: 12, fontFamily: "monospace", color: "#e8f4ff", marginBottom: 3 }}>
                                {o.order_id} · {o.original_vehicle} → overridden
                              </div>
                              <div style={{ fontSize: 11, color: "#4a6080" }}>{o.override_action}</div>
                            </div>
                            <div style={{ textAlign: "right" }}>
                              <div style={{ fontSize: 14, fontFamily: "'Space Mono', monospace", color: "#06d6a0", fontWeight: 700 }}>
                                ₹{(o.estimated_saving_inr || 0).toLocaleString("en-IN")}
                              </div>
                              <div style={{ fontSize: 10, color: "#3a5070" }}>saved</div>
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              )}
            </div>
          )}
        </div>

        {/* Empty state */}
        {!result && !isRunning && (
          <div style={{ textAlign: "center", padding: "60px 0" }}>
            <div style={{ fontSize: 48, marginBottom: 16, opacity: 0.2 }}>⬡</div>
            <div style={{ fontFamily: "'Space Mono', monospace", fontSize: 13, letterSpacing: 2, color: "#1e3050", marginBottom: 12 }}>
              PRESS RUN ORCHESTRATOR TO BEGIN
            </div>
            <div style={{ fontFamily: "'Space Mono', monospace", fontSize: 11, color: "#1a0a2e", letterSpacing: 1 }}>
              OR PRESS ⚖ DEBATE MODE TO SEE AGENTS ARGUE AND REACH CONSENSUS
            </div>
          </div>
        )}

        {/* Footer */}
        <div style={{ marginTop: 40, paddingTop: 20, borderTop: "1px solid #0e2040", display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 8 }}>
          <div style={{ fontSize: 10, fontFamily: "monospace", color: "#1e3050", letterSpacing: 1 }}>
            ADA × GIRLCODE 2026 — BIGGEST WOMEN AI HACKATHON
          </div>
          <div style={{ fontSize: 10, fontFamily: "monospace", color: "#1e3050" }}>
            RouteOptimizer · DemandForecaster · AlertAgent · ArbitratorAgent · Groq SDK
          </div>
        </div>
      </div>

      </>
    );
  }

export default Page;
